svg.script:
const regions = [...document.querySelectorAll('[data-region]')];
const labels = [...document.querySelectorAll('[data-label-region]')];
const tooltip = document.getElementById('tooltip');
const tooltipTitle = document.getElementById('tooltipTitle');
const tooltipDensity = document.getElementById('tooltipDensity');
const tooltipIndustry = document.getElementById('tooltipIndustry');
let selected = document.querySelector('[data-region="高新区"]');
let pinned = false;
let activeFilters = { industry: '全部行业', scale: '全部规模', premiumOnly: false };
const premiumRegions = new Set(['锦江区', '青羊区', '武侯区', '龙泉驿区', '双流区', '郫都区', '温江区', '新都区', '彭州市', '高新区']);
const industryGroups = {
  电子信息: ['电子信息', '软件服务', '数字文创'],
  生物医药: ['生物医药', '文旅康养'],
  先进制造: ['汽车制造', '智能制造', '先进制造', '绿色制造', '家居制造'],
  现代服务: ['金融商务', '总部服务', '商贸服务', '国际物流', '航空物流', '文旅服务', '临空经济'],
  消费农业: ['现代农业', '食品饮料']
};
const regionScales = (region) => {
  if (region.dataset.density === '高') return ['大型企业', '中型企业', '小微企业'];
  if (/制造|医药|物流|临空/.test(region.dataset.industry)) return ['大型企业', '中型企业'];
  if (region.dataset.density === '中') return ['中型企业', '小微企业'];
  return ['小微企业'];
};
const isFilterActive = (filters) => filters.industry !== '全部行业' || filters.scale !== '全部规模' || filters.premiumOnly;
const matchesFilters = (region, filters) => {
  const industryMatch = filters.industry === '全部行业' || (industryGroups[filters.industry] || []).includes(region.dataset.industry);
  const scaleMatch = filters.scale === '全部规模' || regionScales(region).includes(filters.scale);
  const premiumMatch = !filters.premiumOnly || premiumRegions.has(region.dataset.region);
  return industryMatch && scaleMatch && premiumMatch;
};
const estimateCustomers = (visible, filters) => {
  const densityBase = { 高: 125, 中: 74, 低: 37 };
  let total = visible.reduce((sum, region) => sum + densityBase[region.dataset.density], 0);
  if (filters.scale === '大型企业') total *= .31;
  if (filters.scale === '中型企业') total *= .39;
  if (filters.scale === '小微企业') total *= .30;
  if (filters.premiumOnly) total *= .42;
  return Math.max(0, Math.round(total));
};
const applyFilters = (nextFilters = {}) => {
  activeFilters = { ...activeFilters, ...nextFilters };
  const filterActive = isFilterActive(activeFilters);
  const visible = regions.filter((region) => matchesFilters(region, activeFilters));
  regions.forEach((region) => {
    const matches = visible.includes(region);
    region.classList.toggle('is-filtered-out', filterActive && !matches);
    region.classList.toggle('is-filter-match', filterActive && matches);
    region.setAttribute('aria-disabled', filterActive && !matches ? 'true' : 'false');
    region.setAttribute('tabindex', filterActive && !matches ? '-1' : '0');
    const label = document.querySelector('[data-label-region="' + region.dataset.region + '"]');
    label?.classList.toggle('is-filtered-out', filterActive && !matches);
    label?.classList.toggle('is-filter-match', filterActive && matches);
  });
  if (selected?.classList.contains('is-filtered-out')) {
    pinned = false;
    tooltip.classList.remove('is-visible');
  } else if (pinned && selected) {
    renderTooltip(selected);
  }
  window.parent.postMessage({
    type: 'cmb-region-filter-result',
    districts: Math.min(20, visible.length),
    customers: estimateCustomers(visible, activeFilters)
  }, '*');
};
const renderTooltip = (element) => {
  const x = Number(element.dataset.x);
  const y = Number(element.dataset.y);
  const left = Math.max(4, Math.min(198, x - 54));
  const top = y > 62 ? Math.max(4, y - 53) : Math.min(129, y + 9);
  tooltip.setAttribute('transform', 'translate(' + left + ' ' + top + ')');
  tooltipTitle.textContent = element.dataset.region;
  tooltipDensity.textContent = '客户密度：' + element.dataset.density;
  tooltipIndustry.textContent = '主导产业：' + element.dataset.industry;
  tooltip.classList.add('is-visible');
};
const show = (element, persist = false) => {
  const activeLabel = document.querySelector('[data-label-region="' + element.dataset.region + '"]');
  labels.forEach((label) => label.classList.remove('is-preview'));
  activeLabel?.classList.add('is-preview');
  if (persist) {
    regions.forEach((region) => region.classList.remove('is-selected'));
    labels.forEach((label) => label.classList.remove('is-selected'));
    selected = element;
    element.classList.add('is-selected');
    activeLabel?.classList.add('is-selected');
  }
  renderTooltip(element);
};
const hide = () => {
  labels.forEach((label) => label.classList.remove('is-preview'));
  if (pinned && selected) renderTooltip(selected);
  else tooltip.classList.remove('is-visible');
};
const selectRegion = (region) => {
  pinned = true;
  show(region, true);
  window.parent.postMessage({ type: 'cmb-region-select', region: region.dataset.region, density: region.dataset.density, industry: region.dataset.industry }, '*');
};
regions.forEach((region) => {
  region.addEventListener('mouseenter', () => show(region));
  region.addEventListener('mouseleave', hide);
  region.addEventListener('focus', () => show(region));
  region.addEventListener('blur', hide);
  region.addEventListener('click', () => selectRegion(region));
  region.addEventListener('keydown', (event) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      selectRegion(region);
    }
  });
});
window.addEventListener('message', (event) => {
  if (event.data?.type !== 'cmb-region-filter') return;
  applyFilters(event.data.filters);
});
applyFilters(activeFilters);
